// Build platform-specific RSS/API URL from PLATFORM and TARGET.
const platform = '{{PLATFORM}}'.toLowerCase().trim();
const rawTarget = '{{TARGET}}';
const target = rawTarget.replace(/^[@#]/, '').trim();

let url;
if (platform === 'telegram') {
  url = `https://rsshub.app/telegram/channel/${target}`;
} else if (platform === 'twitter' || platform === 'x') {
  url = `https://rsshub.app/twitter/user/${target}`;
} else if (platform === 'instagram') {
  url = `https://rsshub.app/instagram/user/${target}`;
} else if (platform === 'reddit') {
  url = `https://www.reddit.com/r/${target}/.rss`;
} else {
  // Generic fallback: treat as rsshub path
  url = `https://rsshub.app/${platform}/${target}`;
}

return [{ json: { url, platform, target, fetched_at: new Date().toISOString() } }];

// Parse RSS/Atom/JSON response into a standard post format.
const platform = '{{PLATFORM}}'.toLowerCase();
const target = '{{TARGET}}';

// Helper: strip HTML tags.
function stripHtml(html) {
  return (html || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
}

const parsed = [];
for (const item of items) {
  const body = item.json;
  // RSS body is a string (XML) from httpRequest; attempt to parse.
  let posts = [];
  if (typeof body === 'string') {
    // Simple regex extraction of <item> blocks.
    const itemBlocks = body.match(/<item[\s\S]*?<\/item>/gi) || [];
    for (const block of itemBlocks) {
      const getTag = (tag) => {
        const m = block.match(new RegExp(`<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\/${tag}>|<${tag}[^>]*>([^<]*)<\/${tag}>`, 'i'));
        return m ? (m[1] || m[2] || '').trim() : '';
      };
      posts.push({
        id: getTag('guid') || getTag('link'),
        title: stripHtml(getTag('title')),
        link: getTag('link') || getTag('guid'),
        content: stripHtml(getTag('description') || getTag('content:encoded')),
        published_at: getTag('pubDate') || getTag('dc:date') || new Date().toISOString(),
        platform,
        source: target,
      });
    }
  } else if (body && body.items) {
    // Already parsed (JSON feed format).
    posts = body.items.map((p) => ({
      id: p.id || p.url,
      title: stripHtml(p.title || ''),
      link: p.url || p.id,
      content: stripHtml(p.content_html || p.content_text || p.summary || ''),
      published_at: p.date_published || new Date().toISOString(),
      platform,
      source: target,
    }));
  }
  parsed.push(...posts.map((p) => ({ json: p })));
}

return parsed.length > 0 ? parsed : [{ json: { message: 'No posts parsed', platform, source: target } }];

// Deduplicate: only pass through posts not seen before.
const fs = require('fs');
const platform = '{{PLATFORM}}';
const rawTarget = '{{TARGET}}'.replace(/^[@#]/, '');
const stateFile = `/tmp/social_parser_${platform}_${rawTarget}.json`;

let seen = new Set();
try {
  if (fs.existsSync(stateFile)) {
    const data = JSON.parse(fs.readFileSync(stateFile, 'utf8'));
    seen = new Set(data.ids || []);
  }
} catch (e) {
  // State file unreadable — treat all posts as new.
}

const newItems = items.filter((item) => {
  const id = item.json.id || item.json.link || item.json.title;
  return id && !seen.has(id);
});

// Persist updated seen IDs (keep last 2000).
const newIds = newItems.map((i) => i.json.id || i.json.link || i.json.title).filter(Boolean);
newIds.forEach((id) => seen.add(id));
try {
  fs.writeFileSync(stateFile, JSON.stringify({ ids: [...seen].slice(-2000) }));
} catch (e) {
  console.error('State save error:', e.message);
}

if (newItems.length === 0) {
  return [{ json: { message: 'No new posts', platform, checked_at: new Date().toISOString() } }];
}
return newItems;

// Save results to file or just return them.
const fs = require('fs');
const outputPath = '{{OUTPUT}}';

if (outputPath && outputPath !== 'none' && outputPath !== '') {
  try {
    const lines = items.map((i) => JSON.stringify(i.json)).join('\n');
    fs.appendFileSync(outputPath, lines + '\n');
    console.log(`Saved ${items.length} item(s) to ${outputPath}`);
  } catch (e) {
    console.error('File write error:', e.message);
  }
} else {
  console.log(`Social parser result: ${items.length} item(s)`);
  items.forEach((i) => console.log(JSON.stringify(i.json)));
}
return items;
